CREATE TABLE "public"."saved_games" ("id" uuid DEFAULT gen_random_uuid() PRIMARY KEY, "table_id" uuid NOT NULL REFERENCES "public"."tables"("id") ON DELETE CASCADE, "user_id" uuid NOT NULL REFERENCES "public"."profiles"("id") ON DELETE CASCADE, "start_date" date NOT NULL, "end_date" date NOT NULL, "status" text NOT NULL DEFAULT 'active', "attendance_count" integer NOT NULL DEFAULT 0, "renewed_from_id" uuid UNIQUE REFERENCES "public"."saved_games"("id") ON DELETE SET NULL, "created_at" timestamptz NOT NULL DEFAULT now(), "updated_at" timestamptz NOT NULL DEFAULT now(), CONSTRAINT "saved_games_valid_status" CHECK ("status" IN ('active', 'cancelled', 'completed')), CONSTRAINT "saved_games_valid_dates" CHECK ("end_date" >= "start_date"), CONSTRAINT "saved_games_max_duration" CHECK ("end_date" < ("start_date" + interval '3 months')), CONSTRAINT "saved_games_attendance_nonnegative" CHECK ("attendance_count" >= 0), CONSTRAINT "saved_games_no_active_overlap" EXCLUDE USING gist ("table_id" "extensions"."gist_uuid_ops" WITH =, daterange("start_date", "end_date", '[]') WITH &&) WHERE ("status" = 'active'));
